```class Solution {
    public int findUnsortedSubarray(int[] nums) {
        int[] copy = nums.clone();
        Arrays.sort(copy);
        int start = 0, end = nums.length - 1;
        while (start < nums.length && copy[start] == nums[start]) start++;
        while (end >= 0 && copy[end] == nums[end]) end--;
        return end - start + 1;
    }
}```
